effect.script:
function animate(env,el,p) {
    let t = env.time * env.duration * p.freq / 4.0;
    let da, db, dc;
    if( p.basis==0 ) {
        da = AM.simplexNoise(t,0,p.seed);
        db = AM.simplexNoise(0,t*2,p.seed);
        dc = AM.simplexNoise(t*4+234.34,t*4+547.931,p.seed);
    } else {
        da = AM.simplexNoise(el.transform.location.x * p.freq / 500.0, el.transform.location.y * p.freq / 500.0, p.seed);
        db = AM.simplexNoise(el.transform.location.x * p.freq * 2.0 / 500.0, el.transform.location.y * p.freq * 2.0 / 500.0, p.seed+7468.329);
        dc = AM.simplexNoise(el.transform.location.x * p.freq * 4.0 / 500.0, el.transform.location.y * p.freq * 4.0 / 500.0, p.seed+3668.789);
    }
    let magSum = 1.0;
    let mag = p.mag / 2.0;
    magSum *= (1-mag) + (mag*da/2.0);
    p.mag /= 2.0;
    magSum *= (1-mag) + (mag*db);
    p.mag /= 2.0;
    magSum *= (1-mag) + (mag*dc);
    el.alpha *= magSum;
    return el;
}
